#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>
#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_opencl_wrapper.h"

void setdevice(void) {
    int deviceCount = 0;
    cudaGetDeviceCount(&deviceCount);
    if (deviceCount > 1) {
        int max_multiprocessors = 0;
        int max_device = 0;
        cudaDeviceProp properties;
        for (int device = 0; device < deviceCount; device++) {
            cudaGetDeviceProperties(&properties, device);
            if (max_multiprocessors < properties.multiProcessorCount) {
                max_multiprocessors = properties.multiProcessorCount;
                max_device = device;
            }
        }
        cudaSetDevice(max_device);
    }
}

void checkCUDAError(const char *msg) {
    cudaError_t err = cudaGetLastError();
    if (cudaSuccess != err) {
        printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
        fflush(NULL);
        exit(EXIT_FAILURE);
    }
}

__global__ void findK_kernel(long height,
                             knode *knodesD,
                             long knodes_elem,
                             record *recordsD,
                             long *currKnodeD,
                             long *offsetD,
                             int *keysD,
                             record *ansD,
                             int order)
{
    int thid = threadIdx.x;
    int bid = blockIdx.x;

    for (int i = 0; i < height; i++) {
        if ((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] && (knodesD[currKnodeD[bid]].keys[thid + 1] > keysD[bid])) {
            if (knodesD[offsetD[bid]].indices[thid] < knodes_elem) {
                offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
            }
        }
        __syncthreads();
        if (thid == 0) {
            currKnodeD[bid] = offsetD[bid];
        }
        __syncthreads();
    }

    if (knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]) {
        ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
    }
}

void kernel_gpu_cuda_wrapper(record *records,
                            long records_mem,
                            knode *knodes,
                            long knodes_elem,
                            long knodes_mem,
                            int order,
                            long maxheight,
                            int count,
                            long *currKnode,
                            long *offset,
                            int *keys,
                            record *ans)
{
    setdevice();

    knode *d_knodes;
    record *d_records;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaError_t err;

    err = cudaMalloc((void **)&d_records, records_mem);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc records failed\n"); exit(1); }

    err = cudaMalloc((void **)&d_knodes, knodes_mem);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc knodes failed\n"); exit(1); }

    err = cudaMalloc((void **)&d_currKnode, count * sizeof(long));
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc currKnode failed\n"); exit(1); }

    err = cudaMalloc((void **)&d_offset, count * sizeof(long));
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc offset failed\n"); exit(1); }

    err = cudaMalloc((void **)&d_keys, count * sizeof(int));
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc keys failed\n"); exit(1); }

    err = cudaMalloc((void **)&d_ans, count * sizeof(record));
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc ans failed\n"); exit(1); }

    err = cudaMemcpy(d_records, records, records_mem, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy records failed\n"); exit(1); }

    err = cudaMemcpy(d_knodes, knodes, knodes_mem, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy knodes failed\n"); exit(1); }

    err = cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy currKnode failed\n"); exit(1); }

    err = cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy offset failed\n"); exit(1); }

    err = cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy keys failed\n"); exit(1); }

    err = cudaMemcpy(d_ans, ans, count * sizeof(record), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy ans failed\n"); exit(1); }

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = count;

    findK_kernel<<<blocksPerGrid, threadsPerBlock>>>(maxheight, d_knodes, knodes_elem, d_records, d_currKnode, d_offset, d_keys, d_ans, order);
    cudaDeviceSynchronize();
    checkCUDAError("Kernel execution failed");

    err = cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy ans back failed\n"); exit(1); }

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);
}

